#include <torch/extension.h>
#include <cuda_runtime.h>

template<typename scalar_t>
__global__ void cumprod_forward_kernel(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    const int64_t outer_size,
    const int64_t dim_size,
    const int64_t inner_size) {

    // Robust grid-stride loop pattern
    const int64_t total_inner_work = outer_size * inner_size;
    const int64_t tid = blockIdx.x * blockDim.x + threadIdx.x;
    const int64_t stride = blockDim.x * gridDim.x;

    for (int64_t idx = tid; idx < total_inner_work; idx += stride) {
        const int64_t outer_idx = idx / inner_size;
        const int64_t inner_idx = idx % inner_size;

        if (outer_idx >= outer_size || inner_idx >= inner_size) continue;

        const int64_t base_offset = outer_idx * dim_size * inner_size + inner_idx;
        const int64_t stride_inner = inner_size;

        // Sequential cumulative product for each position
        scalar_t prod = static_cast<scalar_t>(1.0);
        for (int64_t d = 0; d < dim_size; ++d) {
            scalar_t val = input[base_offset + d * stride_inner];
            prod *= val;
            output[base_offset + d * stride_inner] = prod;
        }
    }
}

torch::Tensor cumprod_cuda_forward(torch::Tensor input, int64_t dim) {
    // Validate input
    TORCH_CHECK(input.is_cuda(), "Input tensor must be on CUDA device");
    TORCH_CHECK(dim >= 0 && dim < input.dim(), "Invalid dimension");

    // Get tensor dimensions
    auto sizes = input.sizes();
    int64_t dim_size = sizes[dim];

    // Calculate outer and inner dimensions
    int64_t outer_size = 1;
    for (int64_t i = 0; i < dim; ++i) {
        outer_size *= sizes[i];
    }

    int64_t inner_size = 1;
    for (int64_t i = dim + 1; i < input.dim(); ++i) {
        inner_size *= sizes[i];
    }

    // Create output tensor
    auto output = torch::empty_like(input);

    // Calculate robust launch configuration
    int64_t total_work = outer_size * inner_size;
    int64_t block_size = 256;  // Reasonable default
    int64_t grid_size = (total_work + block_size - 1) / block_size;

    // Cap grid size to avoid excessive overhead
    const int64_t max_grid_size = 65535;
    if (grid_size > max_grid_size) {
        grid_size = max_grid_size;
    }

    // Launch kernel with robust grid-stride pattern
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "cumprod_cuda_forward", ([&] {
        cumprod_forward_kernel<scalar_t><<<grid_size, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            outer_size,
            dim_size,
            inner_size
        );
    }));

    return output;
}
"""

